define('UPLOAD_DIR', 'user-files'); // Directory for uploaded file storage (relative to wp-content)
add_action( 'admin_menu', 'register_my_custom_menus' );  
function register_my_custom_menus() { 
    add_menu_page('User Files Uploader Plugin','Upload User File'); //Main Menu Item Title,Menu Description.    
}     
add_action( 'wp_enqueue_scripts', 'load_files' );  
function load_files(){      
    $uploadDir = wp_get_upload_dir(); 
    if ( ! file_exists( $uploadDir['basedir'] . '/'. UPLOAD_DIR ) ) { // Check directory exists, otherwise create it.    
        mkdir(  $uploadDir['basedir'].'/'.UPLOAD_DIR ,0777);  
       } 
    $fileUploadPath = $uploadDir['path'].'/'.UPLOAD_DIR;   
}     
add_action('wp_handle_upload', 'my_custom_upload_handler'); //Hook for handling file uploads.    
function my_custom_upload_handler($overrides) {  
    $file = wp_handle_upload( $overrides, array() ); 
    if ( $file && array_key_exists('error', $file)) { // Check for errors and display them.    
        echo 'Error: '. $file['error'].'<br />';  
       } elseif (!empty($file['url'])){// If file is successfully uploaded, save the url to a variable (optional).   
        $uploadedFileUrl = $file['url'];  // Save URL of upload.    
        echo 'Upload successful: '. $uploadedFileUrl.'<br />';   } else {     
            print_r($overrides);// If no file was uploaded, display the error message and default to our custom handler for other types (like images).   
            $file = $overrides;  // Passing through.    
       }; return $file;} ?>